        return
    }

    visited[i][j] = true
    *sum += grid[i][j]

    dfs(grid, visited, i+1, j, sum)
    dfs(grid, visited, i-1, j, sum)
    dfs(grid, visited, i, j+1, sum)
    dfs(grid, visited, i, j-1, sum)
}
